const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let input = [];
rl.on('line', function(line) {
    input.push(line);
}).on('close', function() {
    let T = +input[0];
    let i = 1;
    while (T--) {
        let [a, b] = input[i++].split(' ').map(x => +x);
        console.log(lcm(a, b));
    }
    function gcd(a, b) {
        if (b === 0) return a;
        return gcd(b, a % b);
    }
    function lcm(a, b) {
        return Math.abs(a * b) / gcd(a, b);
    }
});
